const KEYS=["apiKey","providerId","model","baseUrl","enabled","logLevel","disabledSites"],DEFAULTS={apiKey:"",providerId:"openai",model:"",baseUrl:"",enabled:!0,logLevel:"info",disabledSites:[]};let settingsCache=null,lastFetchTime=0;const CACHE_TTL=1e3;export async function getSettings(forceRefresh=!1){const now=Date.now();if(!forceRefresh&&settingsCache&&now-lastFetchTime<CACHE_TTL)return settingsCache;const raw=await chrome.storage.local.get(KEYS);return settingsCache={apiKey:raw.apiKey||"",providerId:raw.providerId||DEFAULTS.providerId,model:raw.model||"",baseUrl:raw.baseUrl||"",enabled:raw.enabled!==!1,logLevel:raw.logLevel||DEFAULTS.logLevel,disabledSites:raw.disabledSites||[]},lastFetchTime=now,settingsCache}export async function setSettings(partial){await chrome.storage.local.set(partial),settingsCache=null}export function clearSettingsCache(){settingsCache=null}
